#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, k;
        scanf("%d %d", &N, &k);
        long long int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        long long int totalCost = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                long long int distance = (A[i] > A[j]) ? A[i] - A[j] : A[j] - A[i];
                long long int cost = 1;
                for (int l = 0; l < k; l++) {
                    cost = (cost * distance) % MOD;
                }
                totalCost = (totalCost + cost) % MOD;
                totalCost = (totalCost + cost) % MOD;
            }
        }
        printf("%lld\n", totalCost);
    }
    return 0;
}

