import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int k = sc.nextInt();
            long[] A = new long[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextLong();
            }
            long totalCost = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    long distance = Math.abs(A[i] - A[j]);
                    long cost = 1;
                    for (int l = 0; l < k; l++) {
                        cost = (cost * distance) % 1000000007;
                    }
                    totalCost = (totalCost + cost) % 1000000007;
                    totalCost = (totalCost + cost) % 1000000007;
                }
            }
            System.out.println(totalCost);
        }
    }
}

